import { useEffect, useState } from "react";
import API, { getApiError } from "../services/api";
import {
  formatDisplayDate,
  getMembershipState,
  isAttendedToday
} from "../utils/membership";

export default function Attendance() {
  const [customers, setCustomers] = useState([]);
  const [query, setQuery] = useState("");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [message, setMessage] = useState("");
  const [activeCustomerId, setActiveCustomerId] = useState(null);

  useEffect(() => {
    const loadCustomers = async () => {
      setLoading(true);
      setError("");

      try {
        const response = await API.get("/customers");
        setCustomers(response.data);
      } catch (requestError) {
        setError(getApiError(requestError, "Unable to load customer attendance."));
      } finally {
        setLoading(false);
      }
    };

    loadCustomers();
  }, []);

  const filteredCustomers = customers.filter((customer) => {
    const searchValue = query.toLowerCase().trim();
    return (
      !searchValue ||
      customer.fullName.toLowerCase().includes(searchValue) ||
      String(customer.customerId).includes(searchValue) ||
      customer.phone.includes(searchValue)
    );
  });

  const attendedToday = customers.filter((customer) =>
    isAttendedToday(customer.lastAttended)
  ).length;

  const handleMarkAttendance = async (customerId) => {
    setActiveCustomerId(customerId);
    setMessage("");
    setError("");

    try {
      const response = await API.post("/customers/attendance", { customerId });
      setCustomers((current) =>
        current.map((customer) =>
          customer.customerId === customerId ? response.data : customer
        )
      );
      setMessage(`Attendance marked for ${response.data.fullName}.`);
    } catch (requestError) {
      setError(getApiError(requestError, "Unable to mark attendance."));
    } finally {
      setActiveCustomerId(null);
    }
  };

  return (
    <div className="page-stack">
      <section className="page-heading">
        <div>
          <span className="eyebrow">Daily check-ins</span>
          <h2>Attendance tracker</h2>
          <p>
            Search members and mark attendance directly from the customer list.
            The backend updates each member’s `lastAttended` value automatically.
          </p>
        </div>
      </section>

      {message ? <div className="status-banner">{message}</div> : null}
      {error ? <div className="status-banner status-banner--error">{error}</div> : null}

      <section className="summary-strip">
        <div>
          <strong>{loading ? "..." : customers.length}</strong>
          <span>Total members</span>
        </div>
        <div>
          <strong>{loading ? "..." : attendedToday}</strong>
          <span>Checked in today</span>
        </div>
        <div>
          <strong>{loading ? "..." : filteredCustomers.length}</strong>
          <span>Visible results</span>
        </div>
      </section>

      <section className="panel-card">
        <div className="filters-row">
          <label className="field">
            <span>Find a member</span>
            <input
              placeholder="Search by name, phone, or ID"
              value={query}
              onChange={(event) => setQuery(event.target.value)}
            />
          </label>
        </div>

        {loading ? (
          <div className="panel-empty">Loading attendance roster...</div>
        ) : filteredCustomers.length ? (
          <div className="attendance-list">
            {filteredCustomers.map((customer) => {
              const membership = getMembershipState(customer.planEnd);
              const attended = isAttendedToday(customer.lastAttended);

              return (
                <article key={customer.customerId} className="attendance-card">
                  <div className="attendance-card__content">
                    <div>
                      <div className="attendance-card__title">
                        <strong>{customer.fullName}</strong>
                        <span>#{customer.customerId}</span>
                      </div>
                      <p>
                        {customer.phone} • {customer.plan} • Plan ends{" "}
                        {formatDisplayDate(customer.planEnd)}
                      </p>
                    </div>

                    <div className="attendance-card__badges">
                      <span className={`badge badge--${membership.tone}`}>
                        {membership.label}
                      </span>
                      <span className={`badge badge--${attended ? "success" : "neutral"}`}>
                        {attended
                          ? "Checked in today"
                          : `Last visit ${formatDisplayDate(customer.lastAttended)}`}
                      </span>
                    </div>
                  </div>

                  <button
                    className="button"
                    onClick={() => handleMarkAttendance(customer.customerId)}
                    disabled={activeCustomerId === customer.customerId}
                  >
                    {activeCustomerId === customer.customerId
                      ? "Updating..."
                      : "Mark attendance"}
                  </button>
                </article>
              );
            })}
          </div>
        ) : (
          <div className="panel-empty">
            No customers match that search. Try another member name or ID.
          </div>
        )}
      </section>
    </div>
  );
}
